// src/main.tsx — the default Vite / CRA entry point
import { StrictMode } from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';
import './index.css';

createRoot(document.getElementById('root')!).render(
  <StrictMode>
    <App />
  </StrictMode>
);

function App() {
  return (
    <div>
      <LegacyHeader />   {/* not in StrictMode */}
      <StrictMode>
        <NewDashboard />  {/* strict checks only here */}
      </StrictMode>
    </div>
  );
}

// BUG: mutating a variable outside the component during render
let count = 0;

function Counter() {
  count++;                // impure: side effect in render body
  return <p>Rendered {count} times</p>;
  // In StrictMode: shows "2" on first mount because render ran twice
}

// CORRECT: derive display value from state, no external mutation
function Counter() {
  const [count, setCount] = useState(0);
  return (
    <div>
      <p>Count: {count}</p>
      <button onClick={() => setCount(c => c + 1)}>Add</button>
    </div>
  );
}

// BUG: missing cleanup — event listener accumulates
useEffect(() => {
  window.addEventListener('resize', onResize);
  // No return — StrictMode will expose this:
  // the listener is added twice and never removed
}, []);

// CORRECT: return a cleanup function
useEffect(() => {
  window.addEventListener('resize', onResize);
  return () => window.removeEventListener('resize', onResize);
}, []);

// BUG: creating a resource without disposing it
useEffect(() => {
  const socket = new WebSocket(url);
  socket.onmessage = handleMessage;
  // Forgetting to close: StrictMode creates two sockets
}, [url]);

// CORRECT: close in cleanup
useEffect(() => {
  const socket = new WebSocket(url);
  socket.onmessage = handleMessage;
  return () => socket.close();
}, [url]);

function Dashboard() {
  console.log('render');   // prints twice in dev with StrictMode
  return <h1>Dashboard</h1>;
}

// BUG: global mutation inside render
const ids = { next: 0 };

function Item() {
  const id = ++ids.next;   // renders twice → IDs are 1,2 instead of 1
  return <li id={`item-${id}`}>...</li>;
}

// CORRECT: generate the ID once, outside render, or use useId()
function Item() {
  const id = useId();  // React 18+: stable unique ID, SSR-safe
  return <li id={id}>...</li>;
}

// BUG: subscription leaks because cleanup is missing
useEffect(() => {
  eventBus.on('data', handleData);
  // StrictMode: effect runs twice → two subscriptions, handleData called twice per event
}, []);

// CORRECT
useEffect(() => {
  eventBus.on('data', handleData);
  return () => eventBus.off('data', handleData);
}, []);

// Scenario: fetching data and seeing two API calls in the network panel
useEffect(() => {
  fetch('/api/data').then(r => r.json()).then(setData);
}, []);
// StrictMode runs: fetch, cleanup (nothing), fetch again → two requests in dev

// Fix option A: ignore the second response with an AbortController
useEffect(() => {
  const controller = new AbortController();
  fetch('/api/data', { signal: controller.signal })
    .then(r => r.json())
    .then(setData)
    .catch(err => {
      if (err.name !== 'AbortError') throw err;
    });
  return () => controller.abort();
}, []);

// Fix option B: use a data-fetching library (TanStack Query, SWR)
// that handles deduplication, caching, and cleanup automatically
const { data } = useQuery({ queryKey: ['data'], queryFn: fetchData });

// Not pure — reads from Math.random() (different output each call)
function RandomColor() {
  const hue = Math.floor(Math.random() * 360);  // impure
  return <div style={{ background: `hsl(${hue},80%,60%)` }} />;
}

// Pure — random value is in state, set once on mount
function RandomColor() {
  const [hue] = useState(() => Math.floor(Math.random() * 360));
  return <div style={{ background: `hsl(${hue},80%,60%)` }} />;
}
// useState initializer runs once; subsequent renders reuse the same hue

// src/test-utils.tsx
import { render as rtlRender, RenderOptions } from '@testing-library/react';
import React from 'react';

function render(ui: React.ReactElement, options?: RenderOptions) {
  return rtlRender(
    <React.StrictMode>{ui}</React.StrictMode>,
    options
  );
}

export * from '@testing-library/react';
export { render }; // override the default render

import { render, unmountComponentAtNode } from 'react-dom';
import { act } from 'react';

test('clears interval on unmount', () => {
  const div = document.createElement('div');
  document.body.appendChild(div);

  act(() => { render(<TimerDisplay />, div); });
  expect(document.body.querySelector('[data-testid="timer"]')).toBeInTheDocument();

  // Unmount — should not throw or leave dangling intervals
  act(() => { unmountComponentAtNode(div); });
  div.remove();
});

// A component that suspends and resumes — effects must be idempotent
function ProfileCard({ userId }: { userId: string }) {
  const profile = use(fetchProfile(userId)); // suspends until resolved

  useEffect(() => {
    const tracker = analytics.track('profile_viewed', { userId });
    return () => tracker.stop(); // cleanup fires when the boundary suspends again
  }, [userId]);

  return <div>{profile.name}</div>;
}

import React from 'react';
import LegacyWidget from 'third-party-legacy-lib'; // uses old APIs

export function App() {
  return (
    <>
      {/* Modern code — full StrictMode protection */}
      <React.StrictMode>
        <Header />
        <Dashboard />
      </React.StrictMode>

      {/* Legacy widget — temporarily excluded */}
      <LegacyWidget />
    </>
  );
}

// .storybook/preview.js — wrap all stories in StrictMode
import React from 'react';

export const decorators = [
  (Story) => (
    <React.StrictMode>
      <Story />
    </React.StrictMode>
  ),
];
